export interface IMediaAttachment {
    name: string;
    caption?: string;
    url: string;
    type: string;
}
export interface IFileAttachment extends IMediaAttachment {
    type: "file" | "document";
}
export interface IImageAttachment extends IMediaAttachment {
    type: "image";
}
export interface IStickerAttachment extends IMediaAttachment {
    type: "sticker";
}
export interface IVideoAttachment extends IMediaAttachment {
    type: "video";
}
export interface IAudioAttachment extends IMediaAttachment {
    type: "audio";
}
export interface IContactAttachment {
    type: "contact";
    addresses?: {
        city?: string;
        country?: string;
        countryCode?: string;
        state?: string;
        street?: string;
        type?: "HOME" | "WORK";
        zip?: string;
        postOfficeBox?: string;
        extendedAddress?: string;
        latitude?: number;
        longitude?: number;
    }[];
    birthday?: string;
    emails?: {
        email?: string;
        type?: "HOME" | "WORK";
    }[];
    name?: {
        formattedName?: string;
        firstName?: string;
        lastName?: string;
        middleName?: string;
        suffix?: string;
        prefix?: string;
        nickName?: string[];
    };
    org?: {
        company?: string;
        department?: string;
        subDepartment?: string;
        title?: string;
        roles?: string[];
    };
    phones?: {
        phone?: string;
        type?: "HOME" | "WORK";
    }[];
    urls?: {
        url?: string;
        type?: "HOME" | "WORK";
    }[];
    photos?: string[];
    gender?: string;
    languages?: string[];
    timeZone?: string;
    notes?: string[];
}
export interface ILocationAttachment {
    type: "location";
    latitude: number;
    longitude: number;
    name?: string;
    title?: string;
    address?: string;
}
export type TGenericAttachments = IFileAttachment | IImageAttachment | IVideoAttachment | IAudioAttachment;
export type TAttachments = TGenericAttachments | IStickerAttachment | IContactAttachment | ILocationAttachment;
